using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] entries) =>
        entries.Select(e => new OrderItem { ProductName = e.name, Price = e.price, Quantity = e.qty }).ToList();

    #region CreateOrder – happy path

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 25m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45m, order.Total); // 10*2 + 25*1
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueId()
    {
        // Arrange
        var items = CreateItems(("Widget", 5m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.IsNotEmpty(order.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToRecentUtcTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 5m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsGreaterThan(before.AddSeconds(-1), order.CreatedAt);
        Assert.IsLessThan(after.AddSeconds(1), order.CreatedAt);
    }

    #endregion

    #region CreateOrder – validation / exceptions

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 5m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = CreateItems(("Widget", 5m, 1));
        var created = _service.CreateOrder("cust-1", items);

        // Act
        var found = _service.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(found);
        Assert.AreSame(created, found);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        // Arrange
        var items = CreateItems(("Widget", 5m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        // Act
        var results = _service.GetOrdersByCustomer("cust-1");

        // Assert
        Assert.HasCount(2, results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var results = _service.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(results);
    }

    #endregion

    #region CreateOrder – data-driven total calculation

    [TestMethod]
    [DynamicData(nameof(TotalTestData))]
    public void CreateOrder_CalculatesCorrectTotal(
        string description, List<OrderItem> items, decimal expectedTotal)
    {
        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<object[]> TotalTestData =>
    [
        ["Single item",      CreateItems(("A", 10m, 1)),                10m ],
        ["Multiple items",   CreateItems(("A", 10m, 2), ("B", 5m, 3)), 35m ],
        ["High quantity",    CreateItems(("A", 1.5m, 100)),             150m],
    ];

    #endregion
}

